(1, 3, 'CS001', 24, 30, 80, 'Good effort, but some minor errors in definitions and examples.', '{\"total_score\": 24, \"max_score\": 30, \"percent\": 80, \"overall_comment\": \"Good effort, but some minor errors in definitions and examples.\", \"per_question\": [{\"q_no\": \"Q1\", \"max_marks\": 10, \"marks_awarded\": 8, \"brief_feedback\": \"Correctly identified examples, but definition was slightly off.\", \"confidence\": 0.8}, {\"q_no\": \"Q2\", \"max_marks\": 10, \"marks_awarded\": 8, \"brief_feedback\": \"Correctly identified types of Machine Learning, but definition was slightly off.\", \"confidence\": 0.8}, {\"q_no\": \"Q3\", \"max_marks\": 10, \"marks_awarded\": 8, \"brief_feedback\": \"Correctly identified application of Deep Learning, but definition was slightly off.\", \"confidence\": 0.8}]}', '2026-03-04 20:35:41', 'Arjun Kumar'),
(2, 3, 'CS002', 24, 30, 80, 'Good effort, but some areas for improvement.', '{\"total_score\": 24, \"max_score\": 30, \"percent\": 80, \"overall_comment\": \"Good effort, but some areas for improvement.\", \"per_question\": [{\"q_no\": \"Q1\", \"max_marks\": 10, \"marks_awarded\": 8, \"brief_feedback\": \"Your definition is close, but missing the simulation aspect.\", \"confidence\": 0.8}, {\"q_no\": \"Q2\", \"max_marks\": 10, \"marks_awarded\": 6, \"brief_feedback\": \"You\'ve identified some key concepts, but missed others.\", \"confidence\": 0.6}, {\"q_no\": \"Q3\", \"max_marks\": 10, \"marks_awarded\": 10, \"brief_feedback\": \"Excellent explanation of Deep Learning!\", \"confidence\": 1}]}', '2026-03-04 20:35:46', 'Arjun Kumar'),
(3, 3, 'CS003', 16, 30, 53.33, 'Good effort, but needs improvement in understanding the nuances of AI concepts.', '{\"total_score\": 16, \"max_score\": 30, \"percent\": 53.33, \"overall_comment\": \"Good effort, but needs improvement in understanding the nuances of AI concepts.\", \"per_question\": [{\"q_no\": \"Q1\", \"max_marks\": 10, \"marks_awarded\": 4, \"brief_feedback\": \"Your answer lacks depth and clarity. Al is more than just making computers \'act smart\'.\", \"confidence\": 0.4}, {\"q_no\": \"Q2\", \"max_marks\": 10, \"marks_awarded\": 6, \"brief_feedback\": \"Your answer is partially correct. You\'ve identified the main idea, but missed the types of Machine Learning.\", \"confidence\": 0.6}, {\"q_no\": \"Q3\", \"max_marks\": 10, \"marks_awarded\": 6, \"brief_feedback\": \"Your answer is partially correct. You\'ve identified the relationship, but missed the applications of Deep Learning.\", \"confidence\": 0.6}]}', '2026-03-04 20:35:50', 'Arjun Kumar'),
(4, 3, 'CS004', 24, 30, 80, 'Good effort, but some minor errors in definitions.', '{\"total_score\": 24, \"max_score\": 30, \"percent\": 80, \"overall_comment\": \"Good effort, but some minor errors in definitions.\", \"per_question\": [{\"q_no\": \"Q1\", \"max_marks\": 10, \"marks_awarded\": 8, \"brief_feedback\": \"You mentioned chatbots and recommendation systems, but forgot self-driving cars.\", \"confidence\": 0.8}, {\"q_no\": \"Q2\", \"max_marks\": 10, \"marks_awarded\": 6, \"brief_feedback\": \"You correctly mentioned the types of machine learning, but forgot to mention it\'s a subset of AI.\", \"confidence\": 0.6}, {\"q_no\": \"Q3\", \"max_marks\": 10, \"marks_awarded\": 10, \"brief_feedback\": \"Excellent, you correctly defined deep learning!\", \"confidence\": 1.0}]}', '2026-03-04 20:35:54', 'Vishnu Prasad'),
